from itertools import product
Proc=[0,1]
Labels=['a0','a1','a2','a3a','a3b','cs','a4']
def Not(i): return 1-i
def trans(state):
    flag,turn,pc=state; flag=dict(enumerate(flag)); pc=dict(enumerate(pc)); out=[]
    for self in Proc:
        l=pc[self]
        if l=='a0':
            npc=pc.copy(); npc[self]='a1'; out.append(((flag[0],flag[1]),turn,(npc[0],npc[1]),('a0',self)))
        if l=='a1':
            nf=flag.copy(); nf[self]=True; npc=pc.copy(); npc[self]='a2'; out.append(((nf[0],nf[1]),turn,(npc[0],npc[1]),('a1',self)))
        if l=='a2':
            npc=pc.copy(); npc[self]='a3a'; out.append(((flag[0],flag[1]),Not(self),(npc[0],npc[1]),('a2',self)))
        if l=='a3a':
            npc=pc.copy(); npc[self]='a3b' if flag[Not(self)] else 'cs'; out.append(((flag[0],flag[1]),turn,(npc[0],npc[1]),('a3a',self)))
        if l=='a3b':
            npc=pc.copy(); npc[self]='a3a' if turn==Not(self) else 'cs'; out.append(((flag[0],flag[1]),turn,(npc[0],npc[1]),('a3b',self)))
        if l=='cs':
            npc=pc.copy(); npc[self]='a4'; out.append(((flag[0],flag[1]),turn,(npc[0],npc[1]),('cs',self)))
        if l=='a4':
            nf=flag.copy(); nf[self]=False; npc=pc.copy(); npc[self]='a0'; out.append(((nf[0],nf[1]),turn,(npc[0],npc[1]),('a4',self)))
    return out

def inv(s):
    flag,turn,pc=s
    # TypeOK implicit states generated all type ok
    for i in Proc:
        if pc[i] in {'a2','a3a','a3b','cs','a4'} and flag[i] "'!= True: return False
        if pc[i] in {'"'cs','a4'} and pc[Not(i)] in {'a3b','cs','a4'} and turn "'!= i: return False
    return True
states=list(product(product([False,True], repeat=2), Proc, product(Labels, repeat=2)))
bad=[]
for s in states:
    if inv(s):
        for ns in trans(s):
            if not inv(ns[:3]): bad.append((s,ns)); break
print('"'inv states',sum(map(inv,states)),'bad',len(bad))
for b in bad[:20]: print(b)
